const request = require('supertest');
const app = require('../src/app');

describe('Payment API', () => {
  test('should process valid payment', async () => {
    const response = await request(app)
      .post('/api/payment')
      .send({cardNumber: '4532123456789012', amount: 100});
    expect(response.status).toBe(200);
    expect(response.body.success).toBe(true);
  });

  test('should reject invalid card numbers', async () => {
    const response = await request(app)
      .post('/api/payment')
      .send({cardNumber: '1234', amount: 100});
    expect(response.status).toBe(400);
    expect(response.body.error).toBe('Invalid card number');
  });

  test('should validate payment amounts', async () => {
    const response = await request(app)
      .post('/api/payment')
      .send({cardNumber: '4532123456789012', amount: -50});
    expect(response.status).toBe(400);
    expect(response.body.error).toBe('Invalid amount');
  });

  test('should handle duplicate transactions', async () => {
    const txnId = 'TXN-12345';
    await request(app)
      .post('/api/payment')
      .send({cardNumber: '4532123456789012', amount: 100, transactionId: txnId});

    const response = await request(app)
      .post('/api/payment')
      .send({cardNumber: '4532123456789012', amount: 100, transactionId: txnId});

    expect(response.status).toBe(409);
    expect(response.body.error).toBe('Duplicate transaction');
  });

  test('should return transaction ID', async () => {
    const response = await request(app)
      .post('/api/payment')
      .send({cardNumber: '4532123456789012', amount: 100});
    expect(response.body.transactionId).toBeDefined();
  });
});

